"use strict";var test=require("tape");var extend=require("./");var mutableExtend=require("./mutable");test("merge",function(e){var t={a:"foo"};var a={b:"bar"};e.deepEqual(extend(t,a),{a:"foo",b:"bar"});e.end()});test("replace",function(e){var t={a:"foo"};var a={a:"bar"};e.deepEqual(extend(t,a),{a:"bar"});e.end()});test("undefined",function(e){var t={a:undefined};var a={b:"foo"};e.deepEqual(extend(t,a),{a:undefined,b:"foo"});e.deepEqual(extend(a,t),{a:undefined,b:"foo"});e.end()});test("handle 0",function(e){var t={a:"default"};var a={a:0};e.deepEqual(extend(t,a),{a:0});e.deepEqual(extend(a,t),{a:"default"});e.end()});test("is immutable",function(e){var t={};extend(t,{foo:"bar"});e.equal(t.foo,undefined);e.end()});test("null as argument",function(e){var t={foo:"bar"};var a=null;var n=void 0;e.deepEqual(extend(a,t,n),{foo:"bar"});e.end()});test("mutable",function(e){var t={foo:"bar"};mutableExtend(t,{bar:"baz"});e.equal(t.bar,"baz");e.end()});test("null prototype",function(e){var t={a:"foo"};var a=Object.create(null);a.b="bar";e.deepEqual(extend(t,a),{a:"foo",b:"bar"});e.end()});test("null prototype mutable",function(e){var t={foo:"bar"};var a=Object.create(null);a.bar="baz";mutableExtend(t,a);e.equal(t.bar,"baz");e.end()});test("prototype pollution",function(e){var t={};var a='{"__proto__":{"oops":"It works!"}}';e.strictEqual(t.oops,undefined);extend({},a);e.strictEqual(t.oops,undefined);e.end()});test("prototype pollution mutable",function(e){var t={};var a='{"__proto__":{"oops":"It works!"}}';e.strictEqual(t.oops,undefined);mutableExtend({},a);e.strictEqual(t.oops,undefined);e.end()});